INSERT INTO part_external_offers (
  part_id,
  source,
  search_query,
  title,
  image_url,
  supplier_name,
  offer_url,
  low_price,
  raw_payload,
  refreshed_at,
  created_at,
  updated_at
)
SELECT
  p.id,
  'NAVER_SHOPPING_SEARCH',
  s.search_query,
  s.title,
  s.image_url,
  s.supplier_name,
  s.offer_url,
  s.low_price,
  jsonb_build_object('source', 'team-shared-naver-offer-seed', 'offerTitle', s.title, 'supplierName', s.supplier_name),
  now(),
  now(),
  now()
FROM offer_seed s
JOIN parts p ON p.public_id = s.public_id::uuid
ON CONFLICT (part_id, source) WHERE deleted_at IS NULL
DO UPDATE SET
  search_query = EXCLUDED.search_query,
  title = EXCLUDED.title,
  image_url = EXCLUDED.image_url,
  supplier_name = EXCLUDED.supplier_name,
  offer_url = EXCLUDED.offer_url,
  low_price = EXCLUDED.low_price,
  raw_payload = EXCLUDED.raw_payload,
  refreshed_at = now(),
  updated_at = now();

WITH latest_naver_offer AS (
  SELECT part_id, low_price
  FROM part_external_offers
  WHERE source = 'NAVER_SHOPPING_SEARCH'
    AND deleted_at IS NULL
    AND low_price IS NOT NULL
)
UPDATE parts p
SET price = latest_naver_offer.low_price,
    updated_at = now()
FROM latest_naver_offer
WHERE p.id = latest_naver_offer.part_id
  AND p.status = 'ACTIVE'
  AND p.deleted_at IS NULL
  AND p.price <> latest_naver_offer.low_price;

