INSERT INTO price_snapshots (
  part_id,
  price,
  source,
  collected_at,
  raw_payload
)
SELECT
  p.id,
  s.low_price,
  'NAVER_SHOPPING_SEARCH',
  now(),
  jsonb_build_object('source', 'team-shared-naver-offer-seed', 'offerTitle', s.title, 'supplierName', s.supplier_name)
FROM offer_seed s
JOIN parts p ON p.public_id = s.public_id::uuid;
